query:
CREATE TABLE `faqs` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `question` text NOT NULL, `answer` text NOT NULL, `keywords` json, `category` varchar(100), `isActive` boolean NOT NULL DEFAULT true, `matchCount` int NOT NULL DEFAULT 0, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `faqs_id` PRIMARY KEY(`id`));
CREATE TABLE `conversation_flows` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `name` varchar(255) NOT NULL, `description` text, `triggerKeyword` varchar(255), `isActive` boolean NOT NULL DEFAULT true, `steps` json, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `conversation_flows_id` PRIMARY KEY(`id`));
CREATE TABLE `broadcast_campaigns` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `name` varchar(255) NOT NULL, `message` text NOT NULL, `mediaUrl` varchar(1000), `status` enum('draft','scheduled','sending','sent','failed') NOT NULL DEFAULT 'draft', `targetType` enum('all','tag','custom') NOT NULL DEFAULT 'all', `targetTags` json, `recipientCount` int NOT NULL DEFAULT 0, `sentCount` int NOT NULL DEFAULT 0, `deliveredCount` int NOT NULL DEFAULT 0, `readCount` int NOT NULL DEFAULT 0, `failedCount` int NOT NULL DEFAULT 0, `scheduledAt` timestamp, `startedAt` timestamp, `completedAt` timestamp, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `broadcast_campaigns_id` PRIMARY KEY(`id`));
CREATE TABLE `lead_forms` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `name` varchar(255) NOT NULL, `fields` json, `triggerKeyword` varchar(255), `thankYouMessage` text, `isActive` boolean NOT NULL DEFAULT true, `submissionCount` int NOT NULL DEFAULT 0, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `lead_forms_id` PRIMARY KEY(`id`));
CREATE TABLE `activity_logs` (`id` int AUTO_INCREMENT NOT NULL, `businessId` int NOT NULL, `userId` int, `entityType` varchar(50), `entityId` int, `action` varchar(100) NOT NULL, `description` text, `metadata` json, `createdAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `activity_logs_id` PRIMARY KEY(`id`))

